"use strict";parserFactory.registerUrlRule(e=>util.extractHostName(e).endsWith("thetranslation.wordpress.com"),()=>new NanodesuParser);class NanodesuParser extends Parser{constructor(){super()}getChapterUrls(e){let r=e.querySelector("ul#nav");return Promise.resolve(util.hyperlinksToChapterList(r))}findContent(e){return e.querySelector("div.page-body")}findChapterTitle(e){return e.querySelector("h2.page-title")}findParentNodeOfChapterLinkToRemoveAt(e){return util.moveIfParent(e,"p")}}